    for index = 1, 64 do
        local value = string.byte(key, index)
        inner[index] = string.char(BV_BXOR(value, 0x36))
        outer[index] = string.char(BV_BXOR(value, 0x5c))
    end
    return bvSha256(table.concat(outer) .. bvSha256(table.concat(inner) .. message))
